class _Node:
    __slots__ = ("val", "next")
    def __init__(self, val):
        self.val = val
        self.next = None


def _build(values):
    head = None
    tail = None
    for v in values:
        node = _Node(v)
        if head is None:
            head = tail = node
        else:
            tail.next = node
            tail = node
    return head


def merge_two_lists(l1, l2):
    p1 = _build(l1)
    p2 = _build(l2)

    dummy = _Node(None)
    tail = dummy
    while p1 is not None and p2 is not None:
        if p1.val <= p2.val:
            tail.next = p1
            p1 = p1.next
        else:
            tail.next = p2
            p2 = p2.next
        tail = tail.next
    tail.next = p1 if p1 is not None else p2

    out = []
    node = dummy.next
    while node is not None:
        out.append(node.val)
        node = node.next
    return out
